<header class="page-head"><div><span class="eyebrow">Gudang</span><h1>Inventori</h1></div><a class="button" href="<?=url('/admin/stock-opnames')?>">Mulai opname</a></header><section class="panel"><p class="panel-help">Angka positif menambah stok; angka negatif mengurangi stok. Setiap perubahan tercatat.</p><div class="table-wrap" tabindex="0" aria-label="Daftar inventori, geser horizontal bila diperlukan"><table><thead><tr><th>Produk / varian</th><th>SKU</th><th>Stok</th><th>Penyesuaian</th></tr></thead><tbody><?php foreach($items as $x):?><tr><td><strong><?=e($x['product_name'])?></strong><small><?=e($x['name'])?></small></td><td><?=e($x['sku'])?></td><td><span class="stock <?=($x['stock_qty']<=$x['low_stock_threshold'])?'low':''?>"><?=$x['stock_qty']?></span></td><td><form class="inline-form inventory-form" method="post" action="<?=url('/admin/inventory/'.$x['id'].'/adjust')?>" onsubmit="return confirm('Simpan penyesuaian stok ini?')"><?=csrf_field()?><label><span class="sr-only">Perubahan stok <?=e($x['product_name'])?></span><input type="number" name="quantity_change" placeholder="10 atau -2" required></label><label><span class="sr-only">Alasan perubahan</span><input name="notes" placeholder="Alasan perubahan" required></label><button>Simpan</button></form></td></tr><?php endforeach?><?php if(!$items):?><tr><td colspan="4" class="empty-cell">Belum ada varian produk. Tambahkan produk terlebih dahulu.</td></tr><?php endif?></tbody></table></div></section>
